    wwv_flow_api.g_varchar2_table(425) := 'ientes al vencimiento del plazo se\''f1'||wwv_flow.LF||
'alado para declarar, determinar mediante una Liquidaci\''f3n O';
    wwv_flow_api.g_varchar2_table(426) := 'ficial de Aforo la obligaci\''f3n tributaria a cargo del contribuyente, responsable, agente retenedor';
    wwv_flow_api.g_varchar2_table(427) := ' o declarante '||wwv_flow.LF||
'que no haya declarado, para el caso de la normativa contenida en el Distrito de Barra';
    wwv_flow_api.g_varchar2_table(428) := 'nquilla se contempl\''f3 un procedimiento especial y unificado de la sanci\''f3n por no declarar y de ';
    wwv_flow_api.g_varchar2_table(429) := 'la liquidaci\''f3'||wwv_flow.LF||
'n oficial de aforo introducido en el Acuerdo 029 de 2017 en el art\''edculo 29.'||wwv_flow.LF||
'\par';
    wwv_flow_api.g_varchar2_table(430) := ' Para el caso de autos, el t\''e9rmino de cinco (5) a\''f1os para proferir la Liquidaci\''f3n Oficial d';
    wwv_flow_api.g_varchar2_table(431) := 'e Aforo no ha precluido, siendo en consecuencia oportuna la expedici\''f3n del presente acto administ';
    wwv_flow_api.g_varchar2_table(432) := 'rativo.}{\rtlch\fcs1 \af1 \ltrch\fcs0 '||wwv_flow.LF||
'\f1\insrsid1531646\charrsid9181098 '||wwv_flow.LF||
'\par }\pard \ltrpar\s21\q';
    wwv_flow_api.g_varchar2_table(433) := 'c \li0\ri0\sb100\sa100\sbauto1\saauto1\widctlpar\wrapdefault\aspalpha\aspnum\faauto\adjustright\rin0';
