    wwv_flow_api.g_varchar2_table(437) := 'rin0\lin0\itap0\pararsid9181098 {\rtlch\fcs1 \af1 \ltrch\fcs0 \f1\insrsid9181098\charrsid9181098 Con';
    wwv_flow_api.g_varchar2_table(438) := 'tra la presente Liquidaci\''f3'||wwv_flow.LF||
'n Oficial de Aforo, procede el recurso de reconsideraci\''f3n, de confo';
    wwv_flow_api.g_varchar2_table(439) := 'rmidad con lo establecido en el Art\''edculo 313 del Decreto N\''b0 0924 de 2011, - por el cual se ren';
    wwv_flow_api.g_varchar2_table(440) := 'umera la normatividad tributaria del\~ Distrito Especial,\~ Industri'||wwv_flow.LF||
'al y Portuario de Barranquilla ';
    wwv_flow_api.g_varchar2_table(441) := 'contenida en el Decreto 0180 de 2010- el cual podr\''e1 interponerse ante la Administraci\''f3n Tribut';
    wwv_flow_api.g_varchar2_table(442) := 'aria Distrital \endash  Grupo de Discusi\''f3n Tributaria-, dentro del mes siguiente a la notificaci\';
    wwv_flow_api.g_varchar2_table(443) := '''f3'||wwv_flow.LF||
'n del presente acto. El recurso deber\''e1 cumplir con los requisitos exigidos en los Art\''edculo';
    wwv_flow_api.g_varchar2_table(444) := 's 722 a 725 y 729 a 731 del Estatuto Tributario Nacional.'||wwv_flow.LF||
'\par En el evento que el contribuyente des';
