    wwv_flow_api.g_varchar2_table(453) := 'nte presenta la(s) declaraci\''f3n(es) y acepta total o parcialmente los hechos planteados en el pres';
    wwv_flow_api.g_varchar2_table(454) := 'ente acto administrativo, la sanci\''f3n por no declarar se reducir\''e1'||wwv_flow.LF||
' en un cincuenta por ciento (';
    wwv_flow_api.g_varchar2_table(455) := '50%) de la inicialmente impuesta siempre que este valor no sea inferior a la sanci\''f3n por Extempor';
    wwv_flow_api.g_varchar2_table(456) := 'aneidad aplicable por la presentaci\''f3n de la declaraci\''f3n despu\''e9'||wwv_flow.LF||
's del emplazamiento. Para ta';
    wwv_flow_api.g_varchar2_table(457) := 'l efecto el sancionado deber\''e1 presentar un escrito ante el \''e1rea encargada de resolver el recur';
    wwv_flow_api.g_varchar2_table(458) := 'so de reconsideraci\''f3'||wwv_flow.LF||
'n, en el cual consten los hechos aceptados, adjuntando la prueba del pago o ';
    wwv_flow_api.g_varchar2_table(459) := 'acuerdo de pago del impuesto, retenciones y sanciones incluida la sanci\''f3n reducida, en todo caso ';
    wwv_flow_api.g_varchar2_table(460) := 'el resultado de la Sanci\''f3n no debe ser inferior al valor de la sanci\''f3n m'||wwv_flow.LF||
